// Parse the error trigger payload into a structured object.
// Expected prefix format (Contract v1):
//   [SUPPLIER:STAGE] human message | ctx={"key":"value",...}
const payload = $input.first().json;
const exec = payload.execution || {};
const workflowData = exec.workflowData || {};
const error = exec.error || {};

const workflowId = workflowData.id || '';
const workflowName = workflowData.name || 'Unknown';
const executionId = exec.id || '';
const errorNode = (error.node && error.node.name) || 'Unknown';
const rawMessage = String(error.message || '').trim();
const stoppedAt = exec.stoppedAt || new Date().toISOString();

let supplier = null;
let stage = null;
let humanMessage = rawMessage;
const prefixMatch = rawMessage.match(/^\[([A-Z0-9_-]+):([a-z_]+)\]\s*(.*)$/);
if (prefixMatch) {
  supplier = prefixMatch[1];
  stage = prefixMatch[2];
  humanMessage = prefixMatch[3];
}

let ctx = null;
const ctxMatch = humanMessage.match(/^(.*?)\s*\|\s*ctx=(\{.*\})\s*$/);
if (ctxMatch) {
  humanMessage = ctxMatch[1].trim();
  try { ctx = JSON.parse(ctxMatch[2]); }
  catch (_) { ctx = { _parse_error: 'ctx was not valid JSON', _raw: ctxMatch[2] }; }
}

const messageId = (ctx && (ctx.messageId || ctx.message_id)) || null;
const executionUrl = workflowId && executionId
  ? 'https://francemedek.app.n8n.cloud/workflow/' + workflowId + '/executions/' + executionId
  : null;
const gmailUrl = messageId ? 'https://mail.google.com/mail/u/0/#all/' + messageId : null;

return [{
  json: {
    workflowId, workflowName, executionId, executionUrl,
    errorNode, supplier, stage, humanMessage, rawMessage,
    ctx, ctxPretty: ctx ? JSON.stringify(ctx, null, 2) : null,
    messageId, gmailUrl, timestamp: stoppedAt,
  },
}];
